var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"처치했어......?","JPN":"倒した……？","ENG":"... They did it.","TWN":"解決掉了……？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그 네피림을...... 정말로......?","JPN":"あのネフィリムを……本当に……？","ENG":"They really took care of the Nephil.","TWN":"把那個諾菲力給……？真的……？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"처치할 수 있다고 듣긴 했지만...... 솔직히 믿을 수가 없었는데...... 이건......","JPN":"倒せるとは聞いていましたが……正直信じられなかったのに……","ENG":"They said they could, but I didn't believe them. This is...","TWN":"雖然聽到可以把它解決掉，但……說實話我沒有很相信……這……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"흑...... 흐흑......","JPN":"う……ううっ……","ENG":"Hkkk... *Sob*","TWN":"呵……呵呵……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이제...... 먼저 간 대원들을 다시 볼 낯이 생겼어......","JPN":"これでやっと……先に逝った仲間たちに顔向けできます。","ENG":"Finally, I've avenged my comrades...","TWN":"現在……我好像看到了那些犧牲隊員的臉龎……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양. 울지 말아요. 뚝! 기쁜 날이잖아요?","JPN":"カリンさん、泣かないの。こんなに嬉しい日に涙なんて。","ENG":"Karin, don't cry. Please. It's a happy day.","TWN":"卡琳小姐，別哭啊，停！這是值得高興的一天耶。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"끄윽...... 끄윽...... 머, 머리...... 헝클어지니까...... 끄윽...... 만지지 말아요, 시영 씨!","JPN":"うぐっ……ううっ……あ、頭……ぐしゃぐしゃになるから……うう……ほっといてください、シノンさん！","ENG":"*Sob* *Hiccups!* Shiyoung... Y-you're—*Hiccups!*—messing with my hair... Stop!","TWN":"嗚……嗚……頭，頭髮……會亂的……嗚……別摸了……時雨小姐！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"흑...... 흐극......","JPN":"う……ううっ……","ENG":"*Sob* Hhhkkkk...","TWN":"嗚……嗚……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......직접 보지 않았다면 저도 믿기 힘들군요.","JPN":"……自分の目で確かめなかったら、僕も信じられなかったでしょうね。","ENG":"I wouldn't have believed it if I didn't see it with my own eyes.","TWN":"……要不是親眼見過，我也很難相信。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대령님 외에 제 4종 침식체와 정면으로 싸워서 승리할 수 있는 용병들이 있다니......","JPN":"大佐以外にも、第4種侵食体と正面から戦って勝てる傭兵がいるなんて……","ENG":"I didn't know there were others aside from the Colonel who were strong enough to beat Category 4 C.O.","TWN":"除了上校以外，竟然還有傭兵可以與4級侵蝕體正面戰鬥並取勝……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"당신들, 대체 누굽니까?","JPN":"あなた方の正体は一体……？","ENG":"Who on earth are you?","TWN":"你們，到底是什麼人？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"평범한 3류 태스크포스 컴퍼니의 사원들이지.","JPN":"平凡な3流タスクフォースカンパニーの社員さ。","ENG":"Employees of an ordinary, third-rate TASKFORCE company.","TWN":"只是一個普通特遣勢力公司的三流員工而已。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"당신처럼 높은 직책에 있는 사람이 신경 쓸 만한 곳은 아니야.","JPN":"お前のような高い地位の者が気にするようなところではない。","ENG":"Safely off the radar of high-ranking officers like you.","TWN":"這可不是您這種大人物該在意的事情。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"말장난은 그만두시죠!","JPN":"ごまかさないでください！","ENG":"Please stop trifling with me.","TWN":"別開玩笑了！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그러고 보니 어떻게 이곳 일을 알고 왔는지도 의문이군요.","JPN":"そういえば、どうやってここのことを聞きつけてきたのかも謎ですね。","ENG":"And now that I think of it, I don't even know how you knew about all this.","TWN":"而且我也很疑惑，你們是怎麼知道這裡出事的？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"기지 내에서 벌어진 일은 아직 델타 세븐 본대에서도 알아차리지 못했는데!","JPN":"基地のなかで起きたことは、まだデルタセブンの本隊ですら気づいていないのに！","ENG":"Not even the main forces of Delta Seven know what's taking place in this place.","TWN":"基地裡發生的事情，明明連第七三角洲本隊都還沒察覺到！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그런데 당신들은 어떻게 이곳에 일이 벌어진 걸 알고 도착한 겁니까?","JPN":"あなた方はどうやって気づいてやってきたのですか？","ENG":"Did you come here, knowing what was happening?","TWN":"但你們是怎麼知道，而且到達這裡的！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그것도 저런 괴물이 나타날 거라는 걸 미리 알고 있었던 것처럼!","JPN":"しかも、あんな化け物が出現することを、まるで最初からわかっていたかのように！","ENG":"Did you know that monster was about to show up?","TWN":"簡直就像提前知道這裡會出現那種怪物！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};